import{c as a,Q as i,j as p,m as r}from"./chunks/framework.hhGiamYR.js";const d=JSON.parse('{"title":"致尼科洛","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/upper/03-致尼科洛.md","filePath":"research/machiavelli/machiavelli/diplomatic/upper/03-致尼科洛.md"}'),t={name:"research/machiavelli/machiavelli/diplomatic/upper/03-致尼科洛.md"};function c(o,e,l,s,n,m){return i(),p("div",null,[...e[0]||(e[0]=[r('<h1 id="致尼科洛" tabindex="-1">致尼科洛 <a class="header-anchor" href="#致尼科洛" aria-label="Permalink to &quot;致尼科洛&quot;">​</a></h1><p>致尼科洛 · 马基雅维利 奉命出使弗利的女伯爵殿下及其长子奥塔维亚诺阁下 1499年7月12日决议</p><p>你要前往弗利，谒见尊贵的夫人及其长子奥塔维亚诺领主阁下，在向 他们二位致以诚挚敬意之后，递交你所携带的我们致二位的国书，既有给 他们共同的也有分别给二人的，你应该向他们阐明来意。此次出使是因 为他们三番五次地派人请求我们同意今年续签奥塔维亚诺领主的雇佣军</p><p>合同。①你应指出，我们认为我们在此问题上并无义务如此。在适当的时 机，你要通过我方在罗马涅的专员安德里亚 ·德 · 帕齐，来使他们理解我 们的理由。我们相信，那将能够轻而易举地解释我们否决的缘由。你也该 回忆提及此事：1月的最后一天，安德里亚 · 德 · 帕齐以十人委员会的名 义向领主奥塔维亚诺阁下提出续签之事，得到的回答是：他既不再信守合 约，亦不再承担义务，他不会按照这个条约规定为十人委员会等各方利益 效力了。②你还要补充说，这项拒绝是由弗利的一位名叫斯皮努奇奥的大 人起草的。此外，通过我们收到的上述奥塔维亚诺领主在同一天写成的信 件显示，他已表明此意；另外，通过安德里亚 ·德 · 帕齐——他为尊敬的 卡泰丽娜夫人代笔——发出的多封信件表明.她也丝毫不愿做出“同意” 的决定。因此，我们相信领主阁下已不再对我们负有任何义务，我们对他 亦无任何义务；对我们而言，似乎我们做出的种种努力及我们持有的往来 信函足以表明领主阁下并无丝毫意愿，接受此种合同的续签“同意”。此 外，我们在米兰的大使多次写信报告，表示女伯爵夫人曾致信至尊的米兰 公爵。在其回复中，公爵曾建议她接受此项续签“同意”,而她毫无接受 的意愿，声称合同条件苛刻云云，望公爵阁下勿强人所难，致其失去另谋 他就、收益丰厚的机会。所有那些情况都使我们不得不思考，在言行举止 上，他们二位不再愿意保留此项合同。即使所有这些原因都不存在，领主 阁下在4个月内未对我们提出的条件做出回复，也因时过境迁，使我们现 在不可能回到当时签约时的条款， 一切都已经过期了。你要如此这般明确 无误地为我方立场辩护，以使领主阁下了解我们的所作所为全都是出于理 性，原因如上所述。你应当立刻补充说，尽管发生上述种种情况，我们仍 抱有希望，念及他在过去服役期间对我方忠心耿耿，恪尽职守，为了对他</p><p>① 当时的雇佣军合同通常以2年为期限签订，其中第一年被称为“坚定年”( anno fermo,取其双方信守 合同、稳定不变的意思),第二年被称为“同意”( Beneplacitio ), 其含义是给订约双方以选择权，决定 在运行了1年之后是否再继续合同。——中译者注 ②此句原文为拉丁文：Non teneri,nec obligatum esse,cum pro parte Magistratus Decemvirorum,ete.,non fuerint sibi servata capitula conductae suae。——中译者注</p><p>马基雅维利全集 Opere complete di Niccolo Machiavelli</p><p>效忠我城邦时的种种善举表示感谢，我们决定给予二位阁下续签“同意” 条款，在其“坚定年”到期之时开始生效。然而，鉴于目前的形势以及过 往的经验，目前我们依然拥有大量的重骑兵服役，我们希望这一 “同意” 条款按平时编制续签，每年军饷为10000达克特，我们认为此雇佣军合同 应该能够——如果不是在其数量方面，也至少在其稳定性方面——令领主 阁下满意，因为这样一来，较我们在此之前所维持的相同军饷金额及相同 重骑兵人数，此合同的有效期更长了。并且，我们还相信，领主阁下接受 这一条件不仅让自己心满意足，更能使他对我们共和国感激涕零，带着希 望得到我方越来越多恩惠的心思，在其过往的赫赫战功之外表现出新的豁 达大度。你应对他指出，如果该合同条款对于领主阁下而言不是很让人满 意，但它并不意味着有失颜面或者毫无回旋之余地，只要我们共和国将来 能够荡平敌寇，收复国土，恢复国力。领主阁下或许会声称，我方业已提 高了其他雇佣军队长的军饷，对此，你可以游刃有余地向他解释，那些时 候所出现的境况要求我们那么做，你同时也要让他知晓，如果我们现在同 他们签约，既不会有这么宽大的条件，也不会如当初签约之时所必需的那 样通盘考虑，所谓此一时、彼一时，那时双方讨价还价的筹码已大不相 同。如果领主阁下提出他所遭受的损失，你应指出此合同期限已经超过了 2个月，续签对于阁下应该是有利可图之事，我方可以轻而易举地偿付他 的损失。为了达成这些事项，你应充分发挥言辞的功效，并尽量争取你认 为恰当合理的条款，向领主阁下表明，我城真心诚意地期望给予他这样一 个获利的机会，并对他所做出的功绩深表谢意，我们对他充分信任，并指 出我们两国的团结一致非常必要，你还应以令人愉快的话语劝说领主阁下 达成此目的。 务必记住，迅速将出使情形写信告知，以使如果出现任何困难，我们 能够及时回复，筹划解决之道，你应见机行事，不致使领主阁下因我们的 款项并非总是及时到账而心生抱怨。为此目的，你必须以适当的方式向他 表明，我们双方签约，并非出于我们的迫切，而仅仅为了满足他的需要。</p><p>政务与外交著作 Legazioni,commissarie,scritti di governo</p><p>此项花费甚巨，我方不得已有时会延迟支付；你应用适当言辞说明我方托 词，以使领主阁下易于接受。</p><p>国 书①</p><p>尊敬的伊莫拉及弗利领主、亲爱的朋友卡泰丽娜 ·斯福尔扎女伯爵夫人及 奥塔维亚诺 ·德 ·里亚里奥阁下： 尊敬的领主阁下，亲爱的朋友，我们向阁下派出我城邦公民及国务秘 书尼科洛 · 马基雅维利，我们委托他解释诸多事宜，敬请对他满怀信任之 情，我们对此不复多言。再会! 佛罗伦萨市政宫，1499年7月12日 佛罗伦萨共和国正义旗手 马尔切洛②</p><p>执政团致奥塔维亚诺 ·里亚里奥的信③</p><p>杰出卓越的领主阁下： 我们最亲爱的朋友。我们向阁下派出我城邦公民及国务秘书尼科 洛 · 马基雅维利，我们委托他当面向您解释诸多事宜，请给予他最大的信 任，正如我们亲自同您会谈一样。向阁下致以最良好的祝愿。 市政厅签发，1499年7月12日 佛罗伦萨共和国自由官长和正义旗手 马尔切洛</p><p>①原文用拉丁文写成，中译文以楷体字排版，下同。——中译者注 ②相关公文最后的签名马尔切洛( Marcellus) 是指1498- 1521年任佛罗伦萨第 一秘书厅首长(第 一 国 务秘书)的著名学者马尔切洛 · 维尔吉利奥 · 阿德里亚诺 · 贝尔蒂( Marcello Virgilio di Adriano Berti, 1464-1521)。 ——中译者注 ③英译本未收入，依据贝尔泰利编校本译出。 ——中译者注</p><p>Opere complete di Niccolò Machiavelli</p><p>信件1①</p><p>尊敬的诸位大人： 献上我个人诚挚的敬意!我于昨日22点左右到达，立刻就向总指挥阁 下禀报，并按照诸位大人的愿望通报了有关火药、枪炮弹和硝石方面的事 宜，他对我的答复是去年运到这里的全部铁弹——无论大小——都用于对 维柯的围困战；法国人留下的火药有15磅或20磅，在2年前的一次闪电雷 击中被烧毁了，所引起的爆炸毁掉了城堡中存放火药的那一部分。我随 后便派人去找法拉加诺，按照诸位大人的后勤官给我的指令，查问关于 硝石的信息。他回答我说，他只有100磅的存量，但他在那地方有一个朋 友，有大约600磅的火药，尽管那个数量还远远不够，然而，为了不致使 这趟差事落空，我派这个送信的差役将这批火药送交给诸位大人；我请 求阁下即刻支付此项货款，因为我已承诺按照每1000磅40弗罗林的价位 尽快支付。对这批火药称量后，我们发现总重量为587磅；承运人名叫托 马索 ·迪 · 马佐洛，请阁下将我已承诺的货款支付给他，我已经支付了运 费，金额为8.3弗罗林。</p>',17)])])}const u=a(t,[["render",c]]);export{d as __pageData,u as default};
